"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["124690"],{101800(e){e.exports=JSON.parse('{"tag":{"label":"notAvailableFor","permalink":"/sdk/4.9.0/tags/not-available-for","allTagsPath":"/sdk/4.9.0/tags","count":3,"items":[{"id":"guides/user-criteria-guide","title":"User Criteria","description":"User Criteria (user_criteria) are named, reusable access conditions that determine which users can view catalog items, knowledge articles, service portal topics, and other platform content. Required for controlling Service Catalog item visibility\u2014always use instead of ACLs or the roles property for who can see/order catalog items. Unlike ACLs\u2014which control read/write/delete operations on database records\u2014User Criteria define audience membership based on combinations of users, groups, roles, departments, locations, companies, and optional scripts.","permalink":"/sdk/4.9.0/guides/user-criteria-guide"},{"id":"api/usercriteria-api","title":"UserCriteria","description":"Creates a User Criteria record -- a named, reusable access condition that determines which users can view catalog items, knowledge articles, service portal topics, and other platform content (user_criteria).","permalink":"/sdk/4.9.0/api/usercriteria-api"},{"id":"guides/user-criteria-examples-guide","title":"UserCriteria Examples Guide","description":"This guide provides comprehensive, scenario-based examples for working with User Criteria in Fluent. For basic API usage and field definitions, see the usercriteria-api topic. For common mistakes and troubleshooting, see the user-criteria-guide topic.","permalink":"/sdk/4.9.0/guides/user-criteria-examples-guide"}],"unlisted":false}}')}}]);